"use strict";(self.webpackChunkknowledge_base=self.webpackChunkknowledge_base||[]).push([["266"],{6164(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/docs/Marketing","label":"BandMath: Comprehensive Feature Documentation","docId":"Marketing","unlisted":false},{"type":"category","label":"Features","collapsible":true,"collapsed":true,"items":[{"type":"category","label":"Custodial Accounting","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Features/Custodial Accounting/Automated Debt Settlement","label":"Automated Debt Settlement","docId":"Features/Custodial Accounting/Automated Debt Settlement","unlisted":false},{"type":"link","href":"/docs/Features/Custodial Accounting/Shared Expenses & Credits","label":"Shared Expenses & Credits","docId":"Features/Custodial Accounting/Shared Expenses & Credits","unlisted":false}]},{"type":"category","label":"Core Financial Ledger","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Features/Core Financial Ledger/Add, Modify, and Delete Transactions","label":"Add, Modify, and Delete Transactions","docId":"Features/Core Financial Ledger/Add, Modify, and Delete Transactions","unlisted":false},{"type":"link","href":"/docs/Features/Core Financial Ledger/Advanced Profit Splitting (The Penny Catcher)","label":"Advanced Profit Splitting (\\"The Penny Catcher\\")","docId":"Features/Core Financial Ledger/Advanced Profit Splitting (The Penny Catcher)","unlisted":false},{"type":"link","href":"/docs/Features/Core Financial Ledger/Member Balances & Settlements","label":"Member Balances & Settlements","docId":"Features/Core Financial Ledger/Member Balances & Settlements","unlisted":false},{"type":"link","href":"/docs/Features/Core Financial Ledger/Smart Receipt Capture","label":"Smart Receipt Capture","docId":"Features/Core Financial Ledger/Smart Receipt Capture","unlisted":false}]},{"type":"category","label":"Advanced Tour Accounting","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Features/Advanced Tour Accounting/The Venue Split Calculator","label":"The Venue Split Calculator","docId":"Features/Advanced Tour Accounting/The Venue Split Calculator","unlisted":false},{"type":"link","href":"/docs/Features/Advanced Tour Accounting/VAT Bank Integration","label":"VAT Bank Integration","docId":"Features/Advanced Tour Accounting/VAT Bank Integration","unlisted":false}]},{"type":"category","label":"The Point-of-Sale (POS) System","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Features/The Point-of-Sale (POS) System/Cash & Card Tracking","label":"Cash & Card Tracking","docId":"Features/The Point-of-Sale (POS) System/Cash & Card Tracking","unlisted":false},{"type":"link","href":"/docs/Features/The Point-of-Sale (POS) System/Customer Email Capture","label":"Customer Email Capture","docId":"Features/The Point-of-Sale (POS) System/Customer Email Capture","unlisted":false},{"type":"link","href":"/docs/Features/The Point-of-Sale (POS) System/Discounts & Tips","label":"Discounts & Tips","docId":"Features/The Point-of-Sale (POS) System/Discounts & Tips","unlisted":false},{"type":"link","href":"/docs/Features/The Point-of-Sale (POS) System/Dynamic Cart System","label":"Dynamic Cart System","docId":"Features/The Point-of-Sale (POS) System/Dynamic Cart System","unlisted":false}]},{"type":"category","label":"Merch Inventory Management","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Features/Merch Inventory Management/Historical Cost Tracking","label":"Historical Cost Tracking","docId":"Features/Merch Inventory Management/Historical Cost Tracking","unlisted":false},{"type":"link","href":"/docs/Features/Merch Inventory Management/Product & Size Management","label":"Product & Size Management","docId":"Features/Merch Inventory Management/Product & Size Management","unlisted":false},{"type":"link","href":"/docs/Features/Merch Inventory Management/Real-time Stock Depletion","label":"Real-time Stock Depletion","docId":"Features/Merch Inventory Management/Real-time Stock Depletion","unlisted":false}]},{"type":"category","label":"The Merch Analyzer","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Features/The Merch Analyzer/Profit & ROI Tracking","label":"Profit & ROI Tracking","docId":"Features/The Merch Analyzer/Profit & ROI Tracking","unlisted":false},{"type":"link","href":"/docs/Features/The Merch Analyzer/Restock Warnings","label":"Restock Warnings","docId":"Features/The Merch Analyzer/Restock Warnings","unlisted":false},{"type":"link","href":"/docs/Features/The Merch Analyzer/Trophy Awards (Top Performers)","label":"\\"Trophy\\" Awards (Top Performers)","docId":"Features/The Merch Analyzer/Trophy Awards (Top Performers)","unlisted":false}]},{"type":"category","label":"Export & Portability","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Features/Export & Portability/Email Contact List Export","label":"Email Contact List Export","docId":"Features/Export & Portability/Email Contact List Export","unlisted":false},{"type":"link","href":"/docs/Features/Export & Portability/Ledger Export to CSV","label":"Ledger Export to CSV","docId":"Features/Export & Portability/Ledger Export to CSV","unlisted":false}]}]},{"type":"category","label":"Troubleshooting","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/docs/Troubleshooting/Retroactive_VAT","label":"The Retroactive VAT Correction","docId":"Troubleshooting/Retroactive_VAT","unlisted":false},{"type":"link","href":"/docs/Troubleshooting/At_Cost_Member_Purchase","label":"The \\"At-Cost\\" Member Purchase","docId":"Troubleshooting/At_Cost_Member_Purchase","unlisted":false},{"type":"link","href":"/docs/Troubleshooting/Incorrect_Merch_Transaction","label":"The Incorrect Merch Transaction","docId":"Troubleshooting/Incorrect_Merch_Transaction","unlisted":false}]}]},"docs":{"Features/Advanced Tour Accounting/The Venue Split Calculator":{"id":"Features/Advanced Tour Accounting/The Venue Split Calculator","title":"The Venue Split Calculator","description":"Nightly merch settlements are notoriously difficult. BandMath\'s venue split logic automatically calculates the venue\'s cut of gross (or net) sales, subtracts it from the night\'s revenue, and accurately splits the remaining profit among the band members.","sidebar":"tutorialSidebar"},"Features/Advanced Tour Accounting/VAT Bank Integration":{"id":"Features/Advanced Tour Accounting/VAT Bank Integration","title":"VAT Bank Integration","description":"Bands can designate a \\"VAT Bank\\" member. The app automatically calculates and siphons the appropriate tax percentage out of the profit pool and safely parks it in the VAT Bank for government remittance, preventing bands from accidentally spending tax money.","sidebar":"tutorialSidebar"},"Features/Core Financial Ledger/Add, Modify, and Delete Transactions":{"id":"Features/Core Financial Ledger/Add, Modify, and Delete Transactions","title":"Add, Modify, and Delete Transactions","description":"Easily record income (anything from tips to payouts), expenses (like gas, hotels, or gear), and money transfers between members. Full editing capabilities ensure the ledger is always accurate.","sidebar":"tutorialSidebar"},"Features/Core Financial Ledger/Advanced Profit Splitting (The Penny Catcher)":{"id":"Features/Core Financial Ledger/Advanced Profit Splitting (The Penny Catcher)","title":"Advanced Profit Splitting (\\"The Penny Catcher\\")","description":"The backend automatically splits income and expenses equally among active members and it dynamically handles rounding errors (e.g., splitting $10.00 three ways) by seamlessly assigning leftover pennies to members in a rotating fashion, guaranteeing perfectly balanced books down to the cent.","sidebar":"tutorialSidebar"},"Features/Core Financial Ledger/Member Balances & Settlements":{"id":"Features/Core Financial Ledger/Member Balances & Settlements","title":"Member Balances & Settlements","description":"The app continually calculates pairwise debts (who owes who exactly what) so that bands can settle up instantly without any manual math.","sidebar":"tutorialSidebar"},"Features/Core Financial Ledger/Smart Receipt Capture":{"id":"Features/Core Financial Ledger/Smart Receipt Capture","title":"Smart Receipt Capture","description":"Upload and attach receipt images directly to any transaction, ensuring you always have a digital paper trail.","sidebar":"tutorialSidebar"},"Features/Custodial Accounting/Automated Debt Settlement":{"id":"Features/Custodial Accounting/Automated Debt Settlement","title":"Automated Debt Settlement","description":"The app works quietly in the background to solve the complex Debt Settlement problem, continually finding the absolute simplest way for everyone to settle up with the minimum number of money transfers.","sidebar":"tutorialSidebar"},"Features/Custodial Accounting/Shared Expenses & Credits":{"id":"Features/Custodial Accounting/Shared Expenses & Credits","title":"Shared Expenses & Credits","description":"Anyone can pay for anything and automatically debit any combination of the other members. Similarly, anyone can take a payment (like a venue payout) and then credit the other members.","sidebar":"tutorialSidebar"},"Features/Export & Portability/Email Contact List Export":{"id":"Features/Export & Portability/Email Contact List Export","title":"Email Contact List Export","description":"A dedicated button instantly downloads a deduplicated, clean CSV of all fan emails collected during the POS checkout. Bands can seamlessly upload this directly into Mailchimp, Klaviyo, or any other marketing tool.","sidebar":"tutorialSidebar"},"Features/Export & Portability/Ledger Export to CSV":{"id":"Features/Export & Portability/Ledger Export to CSV","title":"Ledger Export to CSV","description":"A one-click button downloads the entire financial history into a perfectly formatted, spreadsheet-ready CSV. It includes every detail (Descriptions, Tips, Individual Splits, Payment Methods, and Receipt URLs) so accountants can do their jobs effortlessly.","sidebar":"tutorialSidebar"},"Features/Merch Inventory Management/Historical Cost Tracking":{"id":"Features/Merch Inventory Management/Historical Cost Tracking","title":"Historical Cost Tracking","description":"BandMath locks in the \\"Cost Goods Sold\\" (COGS) at the time of purchase. If a band buys a batch of shirts for $5 each, and a second batch for $7 each, the app calculates profit using the exact cost of the specific item sold.","sidebar":"tutorialSidebar"},"Features/Merch Inventory Management/Product & Size Management":{"id":"Features/Merch Inventory Management/Product & Size Management","title":"Product & Size Management","description":"Create custom merch items (e.g., \\"Tour Tee\\", \\"Vinyl\\") and manage infinite size variations (S, M, L, XL, etc.).","sidebar":"tutorialSidebar"},"Features/Merch Inventory Management/Real-time Stock Depletion":{"id":"Features/Merch Inventory Management/Real-time Stock Depletion","title":"Real-time Stock Depletion","description":"Every time a cart is checked out in the POS, the inventory count for those specific items and sizes is instantly and automatically deducted.","sidebar":"tutorialSidebar"},"Features/The Merch Analyzer/Profit & ROI Tracking":{"id":"Features/The Merch Analyzer/Profit & ROI Tracking","title":"Profit & ROI Tracking","description":"View high-level metrics like Gross Revenue, Total Profit, Average Order Value, and Total Items Sold.","sidebar":"tutorialSidebar"},"Features/The Merch Analyzer/Restock Warnings":{"id":"Features/The Merch Analyzer/Restock Warnings","title":"Restock Warnings","description":"The backend flags items that are running dangerously low on stock or have completely sold out, allowing bands to re-order before losing out on potential revenue.","sidebar":"tutorialSidebar"},"Features/The Merch Analyzer/Trophy Awards (Top Performers)":{"id":"Features/The Merch Analyzer/Trophy Awards (Top Performers)","title":"\\"Trophy\\" Awards (Top Performers)","description":"The app automatically analyzes sales velocity and awards \\"Trophies\\" to the highest-grossing items (e.g., \\"Peony T-shirt - M is your top earner!\\").","sidebar":"tutorialSidebar"},"Features/The Point-of-Sale (POS) System/Cash & Card Tracking":{"id":"Features/The Point-of-Sale (POS) System/Cash & Card Tracking","title":"Cash & Card Tracking","description":"Seamlessly toggle between Cash and Card checkouts to keep an accurate physical cash box count while tracking digital revenue.","sidebar":"tutorialSidebar"},"Features/The Point-of-Sale (POS) System/Customer Email Capture":{"id":"Features/The Point-of-Sale (POS) System/Customer Email Capture","title":"Customer Email Capture","description":"Fan emails can be optionally captured during checkout for digital receipts or mailing list signups.","sidebar":"tutorialSidebar"},"Features/The Point-of-Sale (POS) System/Discounts & Tips":{"id":"Features/The Point-of-Sale (POS) System/Discounts & Tips","title":"Discounts & Tips","description":"Apply custom discounts to total orders or accept tips from generous fans. The backend automatically distributes tip revenue directly into the band\'s profit pool.","sidebar":"tutorialSidebar"},"Features/The Point-of-Sale (POS) System/Dynamic Cart System":{"id":"Features/The Point-of-Sale (POS) System/Dynamic Cart System","title":"Dynamic Cart System","description":"Easily add multiple products and sizes to a cart.","sidebar":"tutorialSidebar"},"Marketing":{"id":"Marketing","title":"BandMath: Comprehensive Feature Documentation","description":"Last Updated: 2026-06-27","sidebar":"tutorialSidebar"},"Troubleshooting/At_Cost_Member_Purchase":{"id":"Troubleshooting/At_Cost_Member_Purchase","title":"The \\"At-Cost\\" Member Purchase","description":"The Scenario:","sidebar":"tutorialSidebar"},"Troubleshooting/Incorrect_Merch_Transaction":{"id":"Troubleshooting/Incorrect_Merch_Transaction","title":"The Incorrect Merch Transaction","description":"The Scenario:","sidebar":"tutorialSidebar"},"Troubleshooting/Retroactive_VAT":{"id":"Troubleshooting/Retroactive_VAT","title":"The Retroactive VAT Correction","description":"The Scenario:","sidebar":"tutorialSidebar"}}}}')}}]);